                <div className="absolute top-6 left-6 flex flex-col gap-2">
                  <span className={`px-4 py-2 rounded-2xl text-[9px] font-black uppercase shadow-xl border backdrop-blur-md ${getStatusStyle(property.status)}`}>
                    {property.status}
